// Extract latest close price
const timeSeries = $json['Time Series (Daily)'] || {};
const dates = Object.keys(timeSeries);

if (!dates.length) {
  return {
    ...$json,
    CurrentPrice: null,
    InvestedValue: null,
    CurrentValue: null,
    PnL: null,
    PnLPercent: null,
    CAGR: null,
    LastUpdated: new Date().toISOString()
  };
}

const latestDate = dates[0];
const currentPrice = parseFloat(timeSeries[latestDate]['4. close']);

const buyPrice = parseFloat($('Process each stock').item.json.BuyPrice);
const quantity = parseFloat($('Process each stock').item.json.Quantity);
const buyDate = new Date($('Process each stock').item.json.BuyDate);
const now = new Date();

const investedValue = buyPrice * quantity;
const currentValue = currentPrice * quantity;
const pnl = currentValue - investedValue;
const pnlPercent = (pnl / investedValue) * 100;

const yearsHeld = (now - buyDate) / (1000 * 60 * 60 * 24 * 365);
const cagr = yearsHeld > 0
  ? ((currentValue / investedValue) ** (1 / yearsHeld) - 1) * 100
  : null;


// ----------------------------
// MAX DRAWDOWN calculation
// ----------------------------
let peak = -Infinity;
let maxDrawdown = 0;

// Iterate oldest → newest
dates.reverse().forEach(date => {
  const close = parseFloat(timeSeries[date]['4. close']);
  if (close > peak) {
    peak = close;
  }
  const drawdown = (close - peak) / peak;
  if (drawdown < maxDrawdown) {
    maxDrawdown = drawdown;
  }
});

// Convert to percentage
maxDrawdown = maxDrawdown * 100;


// ----------------------------
// Portfolio Health Classification
// ----------------------------
let portfolioStatus = "Watch";

if (cagr >= 15 && maxDrawdown > -20) {
  portfolioStatus = "Healthy";
} else if (cagr < 5 || maxDrawdown <= -35) {
  portfolioStatus = "Risk";
}



return {
  Stock: $json["Meta Data"]["2. Symbol"],
  BuyPrice: buyPrice,
  Quantity: quantity,
  BuyDate: $json.BuyDate,
  CurrentPrice: currentPrice,
  InvestedValue: investedValue,
  CurrentValue: currentValue,
  PnL: pnl,
  PnLPercent: pnlPercent,
  CAGR: cagr,
  MaxDrawdown: maxDrawdown,
  PortfolioStatus: portfolioStatus,
  LastUpdated: new Date().toISOString()
};
